import os
import base64
from openpyxl import Workbook
from openpyxl.styles import Font, Alignment, Border, Side, PatternFill
from openpyxl.drawing.image import Image as XLImage
from io import BytesIO
from datetime import datetime

MESI_IT = ["","Gennaio","Febbraio","Marzo","Aprile","Maggio","Giugno",
           "Luglio","Agosto","Settembre","Ottobre","Novembre","Dicembre"]

# Firma olografa come base64 embedded nel modulo
FIRMA_B64 = ""

def genera_modulo_excel(incassi: list, mese: int, anno: int) -> bytes:
    wb = Workbook()
    ws = wb.active
    ws.title = "Corrispettivi"
    ws.sheet_view.showGridLines = False

    bold   = Font(name="Arial", bold=True, size=11)
    normal = Font(name="Arial", size=11)
    thin   = Side(style="thin", color="AAAAAA")
    b_bot  = Border(bottom=thin)
    b_full = Border(top=thin, bottom=thin, left=thin, right=thin)
    center = Alignment(horizontal="center", vertical="center")
    right  = Alignment(horizontal="right",  vertical="center")
    left   = Alignment(horizontal="left",   vertical="center")
    h_fill = PatternFill("solid", fgColor="F0E4C4")
    t_fill = PatternFill("solid", fgColor="1A1A18")

    def w(row, col, value="", bold_=False, size=11, color="1A1A18",
          align=None, bg=None, num_fmt=None, merge_to=None):
        c = ws.cell(row=row, column=col, value=value)
        c.font = Font(name="Arial", bold=bold_, size=size, color=color)
        c.alignment = align or left
        if bg: c.fill = PatternFill("solid", fgColor=bg)
        if num_fmt: c.number_format = num_fmt
        if merge_to:
            ws.merge_cells(start_row=row, start_column=col,
                           end_row=row, end_column=merge_to)
        return c

    # ── Intestazione ──
    w(2, 2, "CITTÀ DI SUZZARA", True, align=center, merge_to=4)
    w(3, 2, "Prov. Di Mantova", align=center, merge_to=4)
    w(5, 1, "GESTIONE ATTIVITÀ MUSEALE — INCASSI GIORNALIERI", True, merge_to=5)
    w(7, 1, "mese di")
    w(7, 2, f"{MESI_IT[mese]} {anno}", True, 12, "B5892A")

    # ── Intestazioni colonne ──
    for col, testo in enumerate(
        ["data", "ricevuta n.", "quantità biglietti/tessere", "importo", "note — contante/POS"], 1
    ):
        c = ws.cell(row=9, column=col, value=testo)
        c.font = Font(name="Arial", bold=True, size=10)
        c.alignment = center
        c.fill = h_fill
        c.border = b_full

    # ── Righe dati ──
    righe = sorted(incassi, key=lambda x: (x["data"], x.get("numero_ricevuta", 0)))
    row = 10
    totale = 0.0
    for inc in righe:
        ws.row_dimensions[row].height = 15
        data_str = datetime.fromisoformat(inc["data"]).strftime("%d/%m/%Y")
        c1 = ws.cell(row=row, column=1, value=data_str)
        c1.font = normal; c1.alignment = left; c1.border = b_bot
        w(row, 2, inc.get("numero_ricevuta", ""), align=center)
        w(row, 3, inc.get("quantita", ""), align=center)
        c4 = ws.cell(row=row, column=4, value=inc["importo_totale"])
        c4.font = normal; c4.alignment = right
        c4.border = b_bot; c4.number_format = "#,##0.00"
        nota = inc["modalita"] + (f" — {inc['note']}" if inc.get("note") else "")
        w(row, 5, nota, align=left)
        totale += inc["importo_totale"]
        row += 1

    # ── Totale ──
    row += 1
    c = ws.cell(row=row, column=1, value="totale incassato")
    c.font = Font(name="Arial", bold=True, size=11, color="FFFFFF")
    c.alignment = center; c.fill = t_fill
    ws.merge_cells(start_row=row, start_column=1, end_row=row, end_column=3)
    ct = ws.cell(row=row, column=4, value=totale)
    ct.font = Font(name="Arial", bold=True, size=13, color="B5892A")
    ct.alignment = right; ct.fill = t_fill
    ct.border = b_full; ct.number_format = "#,##0.00"

    # ── Firme ──
    row += 2
    data_fine = datetime(anno, mese, 28).strftime("%d/%m/%Y")  # placeholder
    w(row, 1, f"Suzzara, {data_fine}")
    w(row, 4, "FIRMA", True, align=center, merge_to=5)
    row += 1
    w(row, 4, "Erika Vecchietti", True, 12, align=center, merge_to=5)

    # ── Inserisci firma olografa ──
    if FIRMA_B64 and FIRMA_B64 != "":
        try:
            firma_bytes = base64.b64decode(FIRMA_B64)
            firma_buf = BytesIO(firma_bytes)
            img = XLImage(firma_buf)
            img.width = 140
            img.height = 35
            ws.add_image(img, f"D{row + 1}")
        except Exception:
            pass

    # ── Larghezze ──
    ws.column_dimensions["A"].width = 16
    ws.column_dimensions["B"].width = 14
    ws.column_dimensions["C"].width = 22
    ws.column_dimensions["D"].width = 14
    ws.column_dimensions["E"].width = 32

    buf = BytesIO()
    wb.save(buf)
    return buf.getvalue()
